      },
      {
        "항목": "packageName mismatch 대응 원칙",
        "내용": "packageName 불일치가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "기각된제안": [
